mapper.update:
update user_points
set userId = #{userId,jdbcType=BIGINT},
  pointsCount = #{pointsCount,jdbcType=INTEGER},
  pointsRule = #{pointsRule,jdbcType=VARCHAR},
  updateDate = #{updateDate,jdbcType=TIMESTAMP}
where userPointsId = #{userPointsId,jdbcType=BIGINT}

update user_points up
set up.pointsCount = up.pointsCount - #{pointsCount,jdbcType=INTEGER}
where up.userId = #{userId,jdbcType=BIGINT}
and  up.pointsCount >= #{pointsCount,jdbcType=INTEGER}
